using System.Text.RegularExpressions;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.StartsWith(result, "(800)");
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_MatchesPattern()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.Matches(result, new Regex(@"^\(\d{3}\) \d{3}-\d{4}$"));
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber("12345"));
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ReturnsGreetingWithMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_ReturnsGreetingWithTitle()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        Assert.AreEqual("Dear Dr. Jones,", result);
    }

    [TestMethod]
    public void BuildGreeting_Result_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Doe");

        StringAssert.StartsWith(result, "Dear ");
    }

    [TestMethod]
    public void BuildGreeting_Result_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Doe");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_Result_ContainsName()
    {
        var result = _formatter.BuildGreeting("Doe");

        StringAssert.Contains(result, "Doe");
    }

    [TestMethod]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting("   "));
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseDashed()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_StripsNonAlphanumeric()
    {
        var result = _formatter.GenerateSlug("C# is Great!!!");

        Assert.AreEqual("c-is-great", result);
    }

    [TestMethod]
    public void GenerateSlug_LeadingTrailingSpaces_TrimmedResult()
    {
        var result = _formatter.GenerateSlug("  padded title  ");

        StringAssert.DoesNotMatch(result, new Regex(@"^-|-$"));
    }

    [TestMethod]
    public void GenerateSlug_MultiWordTitle_StartsWithFirstWord()
    {
        var result = _formatter.GenerateSlug("Getting Started With MSTest");

        StringAssert.StartsWith(result, "getting");
    }

    [TestMethod]
    public void GenerateSlug_MultiWordTitle_EndsWithLastWord()
    {
        var result = _formatter.GenerateSlug("Getting Started With MSTest");

        StringAssert.EndsWith(result, "mstest");
    }

    [TestMethod]
    public void GenerateSlug_Result_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("My Blog Post #1");

        StringAssert.Matches(result, new Regex(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
    }

    [TestMethod]
    public void GenerateSlug_WhitespaceOnly_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug("   "));
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_ReturnsDollarFormatted()
    {
        var result = _formatter.FormatCurrency(9.5m);

        Assert.AreEqual("$9.50", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(100m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_TwoDecimalPlaces_EndsWithDecimals()
    {
        var result = _formatter.FormatCurrency(7m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        var result = _formatter.FormatCurrency(-15.99m);

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatCurrency_Zero_ReturnsZeroFormatted()
    {
        var result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }

    [TestMethod]
    public void FormatCurrency_LargeAmount_ContainsExpectedDigits()
    {
        var result = _formatter.FormatCurrency(1234567.89m);

        StringAssert.EndsWith(result, "1234567.89");
    }
}

